// Route Poisoning Procedure
PROCEDURE OnNetworkFailure(network, interface):
 // Called when directly connected network goes down

 // Mark route as unreachable (metric 16)
 failedRoute = LookupRouteTable(network)
 IF failedRoute != NULL THEN
 failedRoute.metric = 16
 failedRoute.status = UNREACHABLE

 // Send triggered update immediately (poison reverse)
 SendImmediateUpdate(network, 16, interface)

 // Reset invalid timer
 ResetTimer(failedRoute.invalidTimer, 180 seconds)

 // Start garbage collection
 SetTimer(failedRoute.flushTimer, 240 seconds)
 END IF

 // Also poison reverse: include this route in updates to other interfaces
 // with metric 16 to ensure neighbors know it's unreachable
 FOR EACH otherInterface IN router.interfaces:
 IF otherInterface != interface THEN
 SendUpdate(otherInterface, network, 16)
 END IF
 END FOR
END PROCEDURE
